function doGet(e) {
  // Usar el Logger para registrar todos los parámetros enviados
  Logger.log("Parámetros recibidos: " + JSON.stringify(e.parameter));

  // Obtener los parámetros
  var firstName = e.parameter.firstName || "";
  var lastName = e.parameter.lastName || "";
  var email = e.parameter.email || "";
  var cellPhone = e.parameter.cellPhone || "";
  var workPhone = e.parameter.workPhone || "";
  var address = e.parameter.address || "";
  var org = e.parameter.org || "";
  var title = e.parameter.title || "";
  var birthday = e.parameter.birthday || "";
  var urlJson = e.parameter.url || "";  // El campo que contiene el JSON del sitio web
  var imageUrlJson = e.parameter.image || "";  // El campo que contiene el JSON de la imagen (logo o foto)
  var note = e.parameter.note || "";

  // Loguear el valor crudo del JSON de URL y de imagen
  Logger.log("URL JSON: " + urlJson);
  Logger.log("Image JSON: " + imageUrlJson);

  // Parsear el JSON del campo "url"
  var url = "";
  try {
    var parsedUrl = JSON.parse(urlJson);
    url = parsedUrl.Url;  // Extraer la propiedad "Url"
  } catch (error) {
    url = "https://example.com";  // En caso de error, manejarlo
    Logger.log("Error al parsear URL: " + error);
  }

  // Parsear el JSON del campo "image" (logo o foto)
  var imageUrl = "";
  try {
    var parsedImageUrl = JSON.parse(imageUrlJson);
    imageUrl = parsedImageUrl.Url;  // Extraer la propiedad "Url" de la imagen
  } catch (error) {
    imageUrl = "";  // Si no se envía una imagen válida, dejar vacío
    Logger.log("Error al parsear imagen: " + error);
  }

  // Crear el contenido de la vCard
  var vCardData = "BEGIN:VCARD\n" +
                  "VERSION:3.0\n" +
                  "FN:" + firstName + " " + lastName + "\n" +
                  "N:" + lastName + ";" + firstName + ";;;\n" +
                  "EMAIL;TYPE=INTERNET;TYPE=HOME:" + email + "\n" +
                  "TEL;TYPE=CELL:" + cellPhone + "\n" +
                  "TEL;TYPE=WORK:" + workPhone + "\n" +
                  "ADR;TYPE=HOME:;" + address + "\n" +
                  "ORG:" + org + "\n" +
                  "TITLE:" + title + "\n" +
                  "BDAY:" + birthday + "\n" +
                  "URL:" + url + "\n" +
                  (imageUrl ? "PHOTO;TYPE=URL;VALUE=URI:" + imageUrl + "\n" : "") +  // Etiqueta con TYPE=URL para imágenes en línea
                  "NOTE:" + note + "\n" +
                  "CATEGORIES:myContacts\n" +
                  "END:VCARD";

// Generar el código QR para la vCard
var qrCodeUrl = "https://qrcode.tec-it.com/API/QRCode?data=" + encodeURIComponent(vCardData) + "&backcolor=%23FFFFFF&color=%23000000";

  // Cargar el HTML template
  var template = HtmlService.createTemplateFromFile('Template'); // Se asume que tienes un archivo llamado Template.html

  // Pasar los datos al template
  template.firstName = firstName;
  template.lastName = lastName;
  template.email = email;
  template.cellPhone = cellPhone;
  template.workPhone = workPhone;
  template.address = address;
  template.org = org;
  template.title = title;
  template.birthday = birthday;
  template.qrCodeUrl = qrCodeUrl;  // URL dinámica del QR con la vCard
  template.imageUrl = imageUrl || 'https://www.appsheet.com/template/gettablefileurl?appName=SALESAPPV2-227675214&tableName=STORE&fileName=STORE_Images%2FAaWBLcE-nG4fmEg2KAUVDa.LOGO.144809.png';  // Logo predeterminado si no hay imagen

  // Devolver el HTML renderizado
  return template.evaluate().setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL);
}
